module child(input clk1, input clk2);
  always @(posedge clk1) begin end
  always @(posedge clk2) begin end
endmodule
module parent(input clk);
  child c(.clk1(clk), .clk2(clk));
endmodule

reg [3:0] Memory[0:1];
always @(posedge W0_clk) begin
  if (W0_en) Memory[W0_addr] <= W0_data;
end
assign R0_data = Memory[R0_addr];
